SELECT bs.state AS state, comstock_amy2018_r2_2025_ts_by_state.timestamp AS timestamp, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state JOIN comstock_amy2018_r2_2025_md_by_state_and_county_parquet AS bs ON bs.bldg_id = comstock_amy2018_r2_2025_ts_by_state.bldg_id AND bs.state = comstock_amy2018_r2_2025_ts_by_state.state AND bs.upgrade = 0 AND comstock_amy2018_r2_2025_ts_by_state.upgrade = 0 AND comstock_amy2018_r2_2025_ts_by_state.state = 'CO' AND bs.state = 'CO' GROUP BY 1, 2 ORDER BY 1, 2